"use client";

import { experience, siteContent } from "@/data/site";
import { useLanguage } from "@/components/language-provider";

export function Experience() {
  const { language } = useLanguage();
  const copy = siteContent[language].experience;
  const experienceItems = experience[language];
  const groupedExperience = experienceItems.reduce<Array<{ company: string; items: typeof experienceItems }>>(
    (groups, item) => {
      const currentGroup = groups.find((group) => group.company === item.company);

      if (currentGroup) {
        currentGroup.items.push(item);
        return groups;
      }

      groups.push({ company: item.company, items: [item] });
      return groups;
    },
    [],
  );

  return (
    <section id="experience" className="section-shell">
      <p className="eyebrow">{copy.eyebrow}</p>
      <h2 className="section-title">{copy.title}</h2>

      <div className="mt-6 grid gap-4">
        {groupedExperience.map((group) => (
          <article key={group.company} className="soft-card rounded-2xl p-5">
            <div className="mb-5 flex items-center justify-between gap-4">
              <h3 className="text-xl font-bold text-black">{group.company}</h3>
              <span className="h-px flex-1 bg-black/10" aria-hidden="true" />
            </div>

            <div className="experience-rail grid gap-5">
              {group.items.map((item) => (
                <div key={`${item.role}-${item.period}`} className="experience-role">
                  <div className="flex flex-col gap-2 sm:flex-row sm:items-baseline sm:justify-between">
                    <h4 className="text-base font-bold text-black">{item.role}</h4>
                    <p className="w-fit rounded-full border border-black/10 bg-white/50 px-3 py-1 text-xs font-bold text-black/45">
                      {item.period}
                    </p>
                  </div>
                  <p className="mt-3 text-sm leading-6 text-black/62">{item.description}</p>
                </div>
              ))}
            </div>
          </article>
        ))}
      </div>
    </section>
  );
}
