"use client";

import { siteContent, skillGroups } from "@/data/site";
import { useLanguage } from "@/components/language-provider";

export function Skills() {
  const { language } = useLanguage();
  const copy = siteContent[language].skills;
  const groups = skillGroups[language];

  return (
    <section id="skills" className="section-shell">
      <div className="mb-6">
        <p className="eyebrow">{copy.eyebrow}</p>
        <h2 className="section-title">{copy.title}</h2>
      </div>
      <div className="grid gap-3 sm:grid-cols-2">
        {groups.map((group) => (
          <article key={group.title} className="soft-card rounded-xl p-5">
            <h3 className="text-base font-bold text-black">{group.title}</h3>
            <ul className="mt-4 flex flex-wrap gap-2">
              {group.items.map((item) => (
                <li key={item} className="rounded bg-[#eeeeec] px-2 py-1 text-xs font-semibold text-black/58">
                  {item}
                </li>
              ))}
            </ul>
          </article>
        ))}
      </div>
    </section>
  );
}
