"use client";

import { articles, siteContent } from "@/data/site";
import { useLanguage } from "@/components/language-provider";

export function Notes() {
  const { language } = useLanguage();
  const copy = siteContent[language].notes;
  const articleItems = articles[language];

  return (
    <section id="notes" className="section-shell">
      <p className="eyebrow">{copy.eyebrow}</p>
      <h2 className="section-title">{copy.title}</h2>
      <p className="section-copy mt-4 max-w-2xl">{copy.description}</p>

      <div className="mt-6 grid gap-3">
        {articleItems.map((article) => {
          const cardContent = (
            <>
              <div>
                <p className="text-xs font-bold uppercase tracking-[0.1em] text-black/42">{article.date}</p>
                <h3 className="mt-2 text-lg font-bold text-black">{article.title}</h3>
                <p className="mt-3 text-sm leading-6 text-black/62">{article.description}</p>
                <div className="mt-4 flex flex-wrap gap-2">
                  {article.tags.map((tag) => (
                    <span key={tag} className="rounded bg-[#eeeeec] px-2 py-1 text-[0.7rem] font-semibold text-black/55">
                      {tag}
                    </span>
                  ))}
                </div>
              </div>
              <span className="mt-5 inline-flex w-fit rounded-full border border-black/10 bg-white/50 px-3 py-1 text-xs font-bold text-black/50">
                {article.url ? "Hashnode" : copy.cta}
              </span>
            </>
          );

          return article.url ? (
            <a
              key={article.title}
              href={article.url}
              className="soft-card group rounded-xl p-5 hover:bg-white"
              target="_blank"
              rel="noreferrer"
            >
              {cardContent}
            </a>
          ) : (
            <article key={article.title} className="soft-card rounded-xl p-5">
              {cardContent}
            </article>
          );
        })}
      </div>
    </section>
  );
}
