"use client";

import { projects, siteContent } from "@/data/site";
import { useLanguage } from "@/components/language-provider";

export function Projects() {
  const { language } = useLanguage();
  const copy = siteContent[language].projects;
  const projectItems = projects[language];
  const [featuredProject, ...secondaryProjects] = projectItems;

  return (
    <section id="projects" className="section-shell">
      <div className="mb-6">
        <p className="eyebrow">{copy.eyebrow}</p>
        <h2 className="section-title">{copy.title}</h2>
      </div>

      <div className="grid gap-4">
        {featuredProject ? (
          <article
            className="project-card soft-card group grid overflow-hidden rounded-2xl hover:bg-white sm:grid-cols-[210px_1fr]"
            key={featuredProject.title}
          >
            <div className="project-mark min-h-52 bg-[linear-gradient(135deg,#d9d9d4,#f7f7f4)] p-5">
              <div className="flex h-full flex-col justify-between rounded-xl border border-black/10 bg-white/45 p-4">
                <span className="text-[0.65rem] font-bold uppercase tracking-[0.12em] text-black/45">Featured</span>
                <span className="text-4xl font-bold text-black/70">{featuredProject.title.slice(0, 2)}</span>
              </div>
            </div>
            <div className="p-6">
              <p className="eyebrow">{copy.cardLabel}</p>
              <h3 className="mt-2 text-2xl font-bold tracking-normal text-black">{featuredProject.title}</h3>
              <p className="mt-4 max-w-xl text-base leading-7 text-black/62">{featuredProject.description}</p>
              <div className="mt-5 flex flex-wrap gap-2">
                {featuredProject.stack.slice(0, 7).map((item) => (
                  <span key={item} className="rounded bg-[#eeeeec] px-2 py-1 text-[0.7rem] font-semibold text-black/55">
                    {item}
                  </span>
                ))}
              </div>
              <a href={featuredProject.href} className="mt-6 inline-flex text-sm font-medium text-black hover:translate-x-1">
                {copy.github} <span aria-hidden="true" className="ml-2">-&gt;</span>
              </a>
            </div>
          </article>
        ) : null}

        <div className="grid gap-4 sm:grid-cols-2">
          {secondaryProjects.map((project) => (
            <article key={project.title} className="project-card soft-card group rounded-xl p-5 hover:bg-white">
              <p className="eyebrow">{copy.cardLabel}</p>
              <h3 className="mt-2 text-lg font-bold tracking-normal text-black">{project.title}</h3>
              <p className="mt-3 text-sm leading-6 text-black/62">{project.description}</p>
              <div className="mt-4 flex flex-wrap gap-2">
                {project.stack.slice(0, 4).map((item) => (
                  <span key={item} className="rounded bg-[#eeeeec] px-2 py-1 text-[0.7rem] font-semibold text-black/55">
                    {item}
                  </span>
                ))}
              </div>
              <a href={project.href} className="mt-5 inline-flex text-sm font-medium text-black hover:translate-x-1">
                {copy.github} <span aria-hidden="true" className="ml-2">-&gt;</span>
              </a>
            </article>
          ))}
        </div>
      </div>
    </section>
  );
}
