"use client";

import { links, siteContent } from "@/data/site";
import { useLanguage } from "@/components/language-provider";

const contactLinks = [
  { label: "LinkedIn", href: links.linkedin },
  { label: "GitHub", href: links.github },
];

export function Contact() {
  const { language } = useLanguage();
  const copy = siteContent[language].contact;

  return (
    <section id="contact" className="section-shell pb-12">
      <div className="soft-card rounded-xl p-6">
        <p className="eyebrow">{copy.eyebrow}</p>
        <h2 className="section-title">{copy.title}</h2>
        <p className="section-copy mt-4">{copy.copy}</p>
        <div className="mt-6 flex flex-col gap-3 sm:flex-row">
          {contactLinks.map((link) => (
            <a
              key={link.label}
              href={link.href}
              className="rounded-md border border-black/10 bg-white px-4 py-2 text-center text-sm font-semibold text-black hover:bg-black hover:text-white"
            >
              {link.label}
            </a>
          ))}
        </div>
      </div>
    </section>
  );
}
